"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[32944],{3278:e=>{e.exports=JSON.parse('{"tag":{"label":"physics","permalink":"/dst-api-webdocs/docs/tags/physics","allTagsPath":"/dst-api-webdocs/docs/tags","count":43,"items":[{"id":"game-scripts/components/anchor","title":"Anchor","description":"Manages the raising and lowering state of an anchor attached to a boat, handling drag physics, animation timing, and multiplayer coordination via sailor tasks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/anchor"},{"id":"game-scripts/components/blowinwind","title":"Blowinwind","description":"Simulates wind-driven movement and speed variation for an entity by accumulating velocity in the wind direction and applying it to the locomotor component.","permalink":"/dst-api-webdocs/docs/game-scripts/components/blowinwind"},{"id":"game-scripts/components/boatcannon","title":"Boatcannon","description":"Manages loading, aiming, and firing operations for a boat-mounted cannon, including ammo state tracking and projectile launch with recoil physics.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatcannon"},{"id":"game-scripts/components/boatdrag","title":"Boatdrag","description":"Calculates and applies drag and velocity modifiers to watercraft entities during movement.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatdrag"},{"id":"game-scripts/components/boatdrifter","title":"Boatdrifter","description":"Manages the physics and movement state of a boat entity, including drift detection, physics activation/deactivation, and wake test lifecycle.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatdrifter"},{"id":"game-scripts/components/boatmagnet","title":"Boatmagnet","description":"Manages the magnetic attraction behavior of a boat toward a paired beacon, calculating forces and velocity to pull the boat toward the beacon\'s location while avoiding collisions and adapting to motion.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatmagnet"},{"id":"game-scripts/components/boatphysics","title":"Boatphysics","description":"Manages boat movement, physics, steering, sail/magnet forces, drag, and collision response for watercraft entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatphysics"},{"id":"game-scripts/components/boattrailmover","title":"Boattrailmover","description":"Manages movement and trajectory tracking for a boat entity in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boattrailmover"},{"id":"game-scripts/components/carnivalgameshooter","title":"Carnivalgameshooter","description":"Manages the aiming and shooting mechanics for the carnival shooting mini-game, controlling projectile launch parameters and aim animation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/carnivalgameshooter"},{"id":"game-scripts/components/complexprojectile","title":"Complexprojectile","description":"Manages physics-based projectile trajectories with configurable launch conditions, gravity, and hit/miss callbacks for ranged attacks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/complexprojectile"},{"id":"game-scripts/components/drownable","title":"Drownable","description":"Manages drowning and void-falling logic for entities, including damage application, item dropping, and teleportation behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/drownable"},{"id":"game-scripts/components/expertsailor","title":"Expertsailor","description":"Controls configuration values that modify boat sailing physics and anchor behavior for a boat entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/expertsailor"},{"id":"game-scripts/components/explosive","title":"Explosive","description":"Manages the behavior and effects of explosive entities, including area-of-effect damage, building destruction, ignition of flammable objects, and camera effects upon detonation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/explosive"},{"id":"game-scripts/components/floater","title":"Floater","description":"Manages visual and behavioral effects when an entity enters or remains in water, including wetness application, splash spawning, and floating animations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/floater"},{"id":"game-scripts/components/freezable","title":"Freezable","description":"Manages freeze states, coldness accumulation, and thawing behavior for entities, including visual tinting, shatter effects, and resistance mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/components/freezable"},{"id":"game-scripts/components/groundpounder","title":"Groundpounder","description":"Simulates a radial ground pound attack that triggers delayed damage, destruction, platform pushing, and inventory item launch effects across concentric rings.","permalink":"/dst-api-webdocs/docs/game-scripts/components/groundpounder"},{"id":"game-scripts/components/heavyobstaclephysics","title":"Heavyobstaclephysics","description":"Manages dynamic physics behavior for large in-game obstacles that transition between solid, falling, and pushed states based on proximity and interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/heavyobstaclephysics"},{"id":"game-scripts/components/hullhealth","title":"Hullhealth","description":"Manages hull integrity and leak damage for boats, handling collision impacts, degradation over time, and dynamic leak indicators.","permalink":"/dst-api-webdocs/docs/game-scripts/components/hullhealth"},{"id":"game-scripts/components/inventoryitem","title":"Inventoryitem","description":"Manages item properties and behavior related to inventory interaction, moisture, physics, and owner relationships.","permalink":"/dst-api-webdocs/docs/game-scripts/components/inventoryitem"},{"id":"game-scripts/components/joustsource","title":"Joustsource","description":"Manages the lance-based melee attack logic for jousting entities, including collision detection against targets within the lance\'s arc and pushback/knockback behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/joustsource"},{"id":"game-scripts/map/layout","title":"Layout","description":"Provides utility functions for force-directed layout of nodes in 2D space, including repulsion from walls and points.","permalink":"/dst-api-webdocs/docs/game-scripts/map/layout"},{"id":"game-scripts/components/locomotor","title":"Locomotor","description":"Manages entity movement, pathfinding, and speed calculations, including walking, running, platform hopping, and speed modifier interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/locomotor"},{"id":"game-scripts/components/mast","title":"Mast","description":"Manages sail state and forces for a boat mast, including furling/unfurling mechanics, physics interaction with the boat, and animation synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/components/mast"},{"id":"game-scripts/components/nonslipgritpool","title":"Nonslipgritpool","description":"Provides logic to determine whether a point on the ground is covered in non-slip grit, used to prevent entities from sliding on ice or slippery surfaces.","permalink":"/dst-api-webdocs/docs/game-scripts/components/nonslipgritpool"},{"id":"game-scripts/components/oar","title":"Oar","description":"Handles rowing mechanics for boats, applying directional force and managing rowing success/fail behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oar"},{"id":"game-scripts/components/oceanfishingrod","title":"Oceanfishingrod","description":"Manages the ocean fishing rod\'s casting, targeting, tension tracking, and fish capture logic, acting as the central controller for ocean fishing interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishingrod"},{"id":"game-scripts/components/oceanicemanager","title":"Oceanicemanager","description":"Manages dynamic creation, damage, and destruction of ocean ice tiles in the world map, including entity interactions and visual effects.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanicemanager"},{"id":"game-scripts/components/oceanwhirlportalphysics","title":"Oceanwhirlportalphysics","description":"Simulates physics forces (pull and radial rotation) on entities near an ocean whirlpool portal, and handles interaction with static objects and winch targets.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanwhirlportalphysics"},{"id":"game-scripts/components/physicsmodifiedexternally","title":"Physicsmodifiedexternally","description":"Manages externally applied velocity contributions to an entity\'s physics, aggregating multiple sources and updating physics and locomotor state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/physicsmodifiedexternally"},{"id":"game-scripts/components/pinnable","title":"Pinnable","description":"Manages the pinned state and visual wear-off effect for entities that can be stuck by goo-based attacks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/pinnable"},{"id":"game-scripts/components/platformhopdelay","title":"Platformhopdelay","description":"Manages a delay period measured in frame ticks before allowing a platform-hopping action (e.g., moving between floating platforms) to occur.","permalink":"/dst-api-webdocs/docs/game-scripts/components/platformhopdelay"},{"id":"game-scripts/components/projectile","title":"Projectile","description":"Handles the logic for projectiles, including trajectory, homing, collisions, and throwing behavior in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/components/projectile"},{"id":"game-scripts/components/pushable","title":"Pushable","description":"Enables an entity to be pushed by another entity and maintains relative positioning during the push.","permalink":"/dst-api-webdocs/docs/game-scripts/components/pushable"},{"id":"game-scripts/components/rooted","title":"Rooted","description":"Prevents an entity from moving by stopping physics and applying a speed multiplier of 0 via the locomotor component, while managing lifecycle via sources.","permalink":"/dst-api-webdocs/docs/game-scripts/components/rooted"},{"id":"game-scripts/components/ropebridgemanager","title":"Ropebridgemanager","description":"Manages rope bridge creation, destruction, health tracking, and earthquake damage response across the world grid.","permalink":"/dst-api-webdocs/docs/game-scripts/components/ropebridgemanager"},{"id":"game-scripts/components/slipperyfeet","title":"Slipperyfeet","description":"Manages the accumulation and decay of slippiness on an entity, enabling ice-related movement mechanics and slip events based on speed and environmental factors.","permalink":"/dst-api-webdocs/docs/game-scripts/components/slipperyfeet"},{"id":"game-scripts/components/slipperyfeettarget","title":"Slipperyfeettarget","description":"Marks an entity as a target location where slippery surface effects can be evaluated.","permalink":"/dst-api-webdocs/docs/game-scripts/components/slipperyfeettarget"},{"id":"game-scripts/components/stretcher","title":"Stretcher","description":"Dynamically scales an entity along its facing axis to match the distance to a target entity, commonly used for stretchy visual effects like slingshots or elastic attachments.","permalink":"/dst-api-webdocs/docs/game-scripts/components/stretcher"},{"id":"game-scripts/components/stuckdetection","title":"Stuckdetection","description":"Monitors an entity\'s positional movement to determine if it has become stuck for a specified duration.","permalink":"/dst-api-webdocs/docs/game-scripts/components/stuckdetection"},{"id":"game-scripts/components/walkableplatform","title":"Walkableplatform","description":"Manages a physical platform (e.g., a boat or raft) that players and objects can stand on, handling entity attachment, detachment, and interaction with surrounding systems like drowning, physics halting, and network registration.","permalink":"/dst-api-webdocs/docs/game-scripts/components/walkableplatform"},{"id":"game-scripts/components/walkableplatformmanager","title":"Walkableplatformmanager","description":"Manages the registration, lookup, and update of walkable platforms in the world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/walkableplatformmanager"},{"id":"game-scripts/components/walkableplatformplayer","title":"Walkableplatformplayer","description":"Manages player behavior and camera integration when the player is on a walkable platform (such as a boat), including movement prediction, boat-based camera effects, and zoom handling.","permalink":"/dst-api-webdocs/docs/game-scripts/components/walkableplatformplayer"},{"id":"game-scripts/components/waterphysics","title":"Waterphysics","description":"Applies basic physical properties to entities that interact with water, specifically defining their bounciness (restitution).","permalink":"/dst-api-webdocs/docs/game-scripts/components/waterphysics"}],"unlisted":false}}')}}]);